// Este código asume que el nodo se ejecuta DESPUÉS de Teams
// y queremos combinar info del nodo 'HTTP Request' y del nodo actual.

const endpointItems = $('Filter').all(); // Trae todos los datos del inicio
const currentItems = $input.all(); // Trae los datos que llegan de Teams (con el status)

return currentItems.map((item, index) => {
  // Intentamos buscar el ítem correspondiente por índice o por una clave única (email)
  const originalData = endpointItems.find(e => e.json.email === item.json.email);

  return {
    json: {
      email: item.json.email,
      teams_status: item.json.success ? 'Sent' : 'Error',
      endpoint_payload: originalData ? originalData.json : {},
      timestamp: new Date().toISOString(),
      execution_id: $execution.id
    }
  };
});

